// calendar/holiday-calendar.ts — 节假日数据 + 阴历换算
// Apple Calendar 级别的中美节假日，支持阴历节日
// Lunar data: 1901-2099, auto-generated by cnlunar (196 years)
// Leap months handled correctly via leapIdx

import * as fs from "fs";
import * as path from "path";

// ── Region ────────────────────────────────────────────────────
export type Region = "CN" | "US";

export function getRegion(personDir: string): Region {
  try {
    const raw = JSON.parse(fs.readFileSync(path.join(personDir, "settings.json"), "utf8"));
    return raw.region === "US" ? "US" : "CN";
  } catch {
    return "CN";
  }
}

export function setRegion(personDir: string, region: Region) {
  let settings: any = {};
  try {
    settings = JSON.parse(fs.readFileSync(path.join(personDir, "settings.json"), "utf8"));
  } catch {}
  settings.region = region;
  fs.writeFileSync(path.join(personDir, "settings.json"), JSON.stringify(settings, null, 2));
}

// ── Holiday type ──────────────────────────────────────────────
export interface Holiday {
  date: string;       // YYYY-MM-DD
  name: string;
  emoji: string;
  type: "public" | "observance" | "traditional";
  lunar?: string;
}

// ── Helpers ───────────────────────────────────────────────────
function nthWeekdayOf(year: number, month: number, weekday: number, n: number): string {
  const d = new Date(year, month - 1, 1);
  while (d.getDay() !== weekday) d.setDate(d.getDate() + 1);
  d.setDate(d.getDate() + (n - 1) * 7);
  return d.toISOString().slice(0, 10);
}
function lastWeekdayOf(year: number, month: number, weekday: number): string {
  const d = new Date(year, month, 0);
  while (d.getDay() !== weekday) d.setDate(d.getDate() - 1);
  return d.toISOString().slice(0, 10);
}

// ── US Holidays (Federal + observances, matching Apple Calendar) ──
function usHolidays(year: number): Holiday[] {
  const h: Holiday[] = [
    { date: `${year}-01-01`, name: "New Year's Day", emoji: "", type: "public" },
    { date: nthWeekdayOf(year, 1, 1, 3), name: "Martin Luther King Jr. Day", emoji: "", type: "public" },
    { date: nthWeekdayOf(year, 2, 1, 3), name: "Presidents' Day", emoji: "", type: "public" },
    { date: lastWeekdayOf(year, 5, 1), name: "Memorial Day", emoji: "", type: "public" },
    { date: `${year}-06-19`, name: "Juneteenth", emoji: "", type: "public" },
    { date: `${year}-07-04`, name: "Independence Day", emoji: "", type: "public" },
    { date: nthWeekdayOf(year, 9, 1, 1), name: "Labor Day", emoji: "", type: "public" },
    { date: nthWeekdayOf(year, 10, 1, 2), name: "Columbus Day", emoji: "", type: "public" },
    { date: `${year}-11-11`, name: "Veterans Day", emoji: "", type: "public" },
    { date: nthWeekdayOf(year, 11, 4, 4), name: "Thanksgiving", emoji: "", type: "public" },
    { date: `${year}-12-25`, name: "Christmas Day", emoji: "", type: "public" },
  ];
  h.push(
    { date: `${year}-02-14`, name: "Valentine's Day", emoji: "", type: "observance" },
    { date: `${year}-03-17`, name: "St. Patrick's Day", emoji: "", type: "observance" },
    { date: `${year}-10-31`, name: "Halloween", emoji: "", type: "observance" },
    { date: `${year}-12-24`, name: "Christmas Eve", emoji: "", type: "observance" },
    { date: `${year}-12-31`, name: "New Year's Eve", emoji: "", type: "observance" },
  );
  // Easter (Gauss algorithm)
  const a = year % 19, b = Math.floor(year / 100), c = year % 100;
  const d = Math.floor(b / 4), e = b % 4, f = Math.floor((b + 8) / 25);
  const g = Math.floor((b - f + 1) / 3);
  const hh = (19 * a + b - d - g + 15) % 30;
  const i = Math.floor(c / 4), k = c % 4;
  const l = (32 + 2 * e + 2 * i - hh - k) % 7;
  const m = Math.floor((a + 11 * hh + 22 * l) / 451);
  const mo = Math.floor((hh + l - 7 * m + 114) / 31);
  const da = ((hh + l - 7 * m + 114) % 31) + 1;
  const easter = `${year}-${String(mo).padStart(2, "0")}-${String(da).padStart(2, "0")}`;
  h.push({ date: easter, name: "Easter", emoji: "", type: "observance" });
  const ed = new Date(easter + "T00:00:00");
  ed.setDate(ed.getDate() - 2);
  h.push({ date: ed.toISOString().slice(0, 10), name: "Good Friday", emoji: "", type: "observance" });
  h.push({ date: nthWeekdayOf(year, 5, 0, 2), name: "Mother's Day", emoji: "", type: "observance" });
  h.push({ date: nthWeekdayOf(year, 6, 0, 3), name: "Father's Day", emoji: "", type: "observance" });
  return h;
}

