// ── Lunar calendar names ─────────────────────────────────────
const LUNAR_MONTH = ["正","二","三","四","五","六","七","八","九","十","冬","腊"];
const LUNAR_DAY = ["初一","初二","初三","初四","初五","初六","初七","初八","初九","初十","十一","十二","十三","十四","十五","十六","十七","十八","十九","二十","廿一","廿二","廿三","廿四","廿五","廿六","廿七","廿八","廿九","三十"];

// ── solarToLunar: Convert solar date to lunar date ───────────
export interface LunarDate {
  lunarYear: number;
  lunarMonth: number;   // 1-12
  lunarDay: number;     // 1-30
  isLeap: boolean;
  monthName: string;    // e.g. "六" or "闰六"
  dayName: string;      // e.g. "初五"
}

export function solarToLunar(solarDate: string): LunarDate | null {
  const d = new Date(solarDate + "T00:00:00");
  if (isNaN(d.getTime())) return null;

  // Find the lunar year this date belongs to
  // A date belongs to lunar year Y if it is >= CNY of Y and < CNY of Y+1
  let lunarYear = d.getFullYear();

  // Check if date is before CNY of this solar year
  const thisYearData = LUNAR_DATA[lunarYear];
  if (thisYearData) {
    const cnyThis = new Date(thisYearData.cny + "T00:00:00");
    if (d < cnyThis) {
      lunarYear--;
    }
  }

  // Verify: check if date >= CNY of next year
  const nextYearData = LUNAR_DATA[lunarYear + 1];
  if (nextYearData) {
    const cnyNext = new Date(nextYearData.cny + "T00:00:00");
    if (d >= cnyNext) {
      lunarYear++;
    }
  }

  const data = LUNAR_DATA[lunarYear];
  if (!data) return null;

  // Iterate through months to find the right one
  const cny = new Date(data.cny + "T00:00:00");
  let cursor = new Date(cny);
  const totalMonths = data.lengths.length;

  for (let i = 0; i < totalMonths; i++) {
    const monthLen = data.lengths[i];
    const nextCursor = new Date(cursor);
    nextCursor.setDate(nextCursor.getDate() + monthLen);

    if (d >= cursor && d < nextCursor) {
      const dayOffset = Math.floor((d.getTime() - cursor.getTime()) / 86400000);
      const lunarDay = dayOffset + 1;

      // Determine month number and leap status
      // leapIdx points to the REGULAR month; leap month is at leapIdx+1
      let lunarMonth: number;
      let isLeap = false;

      if (data.leapIdx === null) {
        lunarMonth = i + 1;
      } else if (i === data.leapIdx + 1) {
        lunarMonth = data.leapIdx + 1;
        isLeap = true;
      } else if (i > data.leapIdx + 1) {
        lunarMonth = i;  // shift: leap month takes one slot
      } else {
        lunarMonth = i + 1;
      }

      const monthIdx = lunarMonth - 1;
      const monthName = isLeap ? `闰${LUNAR_MONTH[monthIdx]}` : LUNAR_MONTH[monthIdx];
      const dayName = LUNAR_DAY[lunarDay - 1] || String(lunarDay);

      return {
        lunarYear,
        lunarMonth,
        lunarDay,
        isLeap,
        monthName,
        dayName,
      };
    }

    cursor = nextCursor;
  }

  return null;
}

// ── lunarDate: Convert lunar date to solar date ──────────────
export function lunarDate(lunarYear: number, lunarMonth: number, lunarDay: number, isLeap = false): string {
  const data = LUNAR_DATA[lunarYear];
  if (!data) return "";

  // Calculate the target month index in the lengths array
  // leapIdx points to REGULAR month, leap month is at leapIdx+1
  let targetIdx: number;
  if (data.leapIdx === null) {
    targetIdx = lunarMonth - 1;
  } else if (isLeap && lunarMonth === data.leapIdx + 1) {
    targetIdx = data.leapIdx + 1;  // leap month is right after its regular counterpart
  } else if (lunarMonth > data.leapIdx + 1) {
    targetIdx = lunarMonth;  // months after leap shift by 1
  } else {
    targetIdx = lunarMonth - 1;
  }

  if (targetIdx < 0 || targetIdx >= data.lengths.length) return "";

  // Sum days from CNY to the target month start
  const cny = new Date(data.cny + "T00:00:00");
  let days = 0;
  for (let i = 0; i < targetIdx; i++) {
    days += data.lengths[i];
  }
  days += lunarDay - 1;

  const result = new Date(cny);
  result.setDate(result.getDate() + days);
  return result.toISOString().slice(0, 10);
}

// ── 清明节: 太阳黄经15° ──────────────────────────────────────
// Accurate algorithm instead of hardcoded table
function qingmingDate(year: number): string {
  // Qingming is around April 4-6 each year
  // Using the formula: 清明日期 = (Y*D+C)-L
  // Y = year % 100, D = 0.2422, C = 4.81 (for 20th century) or 5.59 (for 21st century)
  // L = Math.floor(Y/4)
  const Y = year % 100;
  const D = 0.2422;
  const C = year < 2000 ? 4.81 : (year < 2100 ? 5.59 : 5.59); // simplified
  const L = Math.floor(Y / 4);
  const day = Math.floor(Y * D + C) - L;
  return `${year}-04-${String(day).padStart(2, "0")}`;
}

// ── China Holidays (法定节假日 + 传统节日) ──
function cnHolidays(year: number): Holiday[] {
  const h: Holiday[] = [];

  h.push({ date: `${year}-01-01`, name: "元旦", emoji: "", type: "public" });

  // 春节 (正月初一 + 除夕 + 初二 + 初三)
  const sf = lunarDate(year, 1, 1);
  if (sf) {
    const eve = new Date(sf + "T00:00:00"); eve.setDate(eve.getDate() - 1);
    // Get correct lunar label for 除夕
    const eveLunar = solarToLunar(eve.toISOString().slice(0, 10));
    const eveLabel = eveLunar ? `${eveLunar.monthName}月${eveLunar.dayName}` : "腊月三十";
    h.push({ date: eve.toISOString().slice(0, 10), name: "除夕", emoji: "", type: "traditional", lunar: eveLabel });

    const d2 = new Date(sf + "T00:00:00"); d2.setDate(d2.getDate() + 1);
    const d3 = new Date(sf + "T00:00:00"); d3.setDate(d3.getDate() + 2);
    h.push({ date: sf, name: "春节", emoji: "", type: "public", lunar: "正月初一" });
    h.push({ date: d2.toISOString().slice(0, 10), name: "春节·初二", emoji: "", type: "public" });
    h.push({ date: d3.toISOString().slice(0, 10), name: "春节·初三", emoji: "", type: "public" });
  }

  // 元宵节 (正月十五)
  const yx = lunarDate(year, 1, 15);
  if (yx) h.push({ date: yx, name: "元宵节", emoji: "", type: "traditional", lunar: "正月十五" });

  // 清明节
  h.push({ date: qingmingDate(year), name: "清明节", emoji: "", type: "public" });

  // 劳动节
  h.push({ date: `${year}-05-01`, name: "劳动节", emoji: "", type: "public" });

  // 端午节 (五月初五)
  const db = lunarDate(year, 5, 5);
  if (db) h.push({ date: db, name: "端午节", emoji: "", type: "public", lunar: "五月初五" });

  // 七夕 (七月初七)
  const qx = lunarDate(year, 7, 7);
  if (qx) h.push({ date: qx, name: "七夕", emoji: "", type: "traditional", lunar: "七月初七" });

  // 中元节 (七月十五)
  const zy = lunarDate(year, 7, 15);
  if (zy) h.push({ date: zy, name: "中元节", emoji: "", type: "traditional", lunar: "七月十五" });

  // 中秋节 (八月十五)
  const ma = lunarDate(year, 8, 15);
  if (ma) h.push({ date: ma, name: "中秋节", emoji: "", type: "public", lunar: "八月十五" });

  // 重阳节 (九月初九)
  const cy = lunarDate(year, 9, 9);
  if (cy) h.push({ date: cy, name: "重阳节", emoji: "", type: "traditional", lunar: "九月初九" });

  // 国庆
  h.push({ date: `${year}-10-01`, name: "国庆节", emoji: "", type: "public" });
  h.push({ date: `${year}-10-02`, name: "国庆节·第2天", emoji: "", type: "public" });
  h.push({ date: `${year}-10-03`, name: "国庆节·第3天", emoji: "", type: "public" });

  // 腊八 (腊月初八)
  const lb = lunarDate(year, 12, 8);
  if (lb) h.push({ date: lb, name: "腊八节", emoji: "", type: "traditional", lunar: "腊月初八" });

  // 小年 (腊月廿三)
  const xn = lunarDate(year, 12, 23);
  if (xn) h.push({ date: xn, name: "小年", emoji: "", type: "traditional", lunar: "腊月廿三" });

  return h;
}

// ── Public API ────────────────────────────────────────────────
export function getHolidays(region: Region, year: number): Holiday[] {
  return region === "US" ? usHolidays(year) : cnHolidays(year);
}

export function getHolidaysForDate(region: Region, date: string): Holiday[] {
  const year = parseInt(date.slice(0, 4));
  return getHolidays(region, year).filter(h => h.date === date);
}

export function getHolidaysForRange(region: Region, start: string, end: string): Holiday[] {
  const sy = parseInt(start.slice(0, 4)), ey = parseInt(end.slice(0, 4));
  const all: Holiday[] = [];
  for (let y = sy; y <= ey; y++) all.push(...getHolidays(region, y));
  return all.filter(h => h.date >= start && h.date <= end);
}
